CREATE OR REPLACE FUNCTION fpa_com_rec_get_vourcher_no (as_receipt_no CHAR) RETURNS varchar AS $body$
DECLARE

  ls_vourcher_no sc_fin_vourcher_head.vourcher_no%type;

BEGIN
  select distinct(coalesce(sc_fin_vourcher_head.receipt_print,'<NEW>'))  into STRICT ls_vourcher_no
  FROM sc_rep_receipt, sc_com_m_receipt
LEFT OUTER JOIN sc_fin_vourcher_head ON (sc_com_m_receipt.vourcher_no = sc_fin_vourcher_head.vourcher_no)
WHERE (sc_rep_receipt.receipt_no = sc_com_m_receipt.receipt_no ) and (sc_rep_receipt.receipt_no = as_receipt_no );

  return trim(both ls_vourcher_no);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
